216→      systems = [
217→        "x86_64-linux"
218→        "aarch64-darwin"
219→      ];
220→
221→      imports = [
222→        treefmt-nix.flakeModule
223→        inputs.git-hooks.flakeModule
224→      ];
225→
226→      perSystem =
227→        {
228→          pkgs,
229→          system,
230→          config,
231→          ...
232→        }:
233→        let
234→          isDarwin = builtins.match ".*-darwin" system != null;
235→          darwinHostname = "M2-MacBook-Air";
236→          nom = "${pkgs.nix-output-monitor}/bin/nom";
237→          allPkgs = mkPkgs system;
238→        in
239→        {
240→          packages = {
241→            inherit (allPkgs)
242→              difit
243→              jj-desc
244→              keifu
245→              polycat
246→              pretty-ts-errors-markdown
247→              similarity-ts
248→              ;
249→          };
250→          apps = {
251→            build = {
252→              type = "app";
253→              program = toString (
254→                pkgs.writeShellScript "build" ''
255→                  set -e
256→                  ${
257→                    if isDarwin then
258→                      ''
259→                        echo "Building darwin configuration..."
260→                        ${nom} build ".#darwinConfigurations.${darwinHostname}.system"
261→                      ''
262→                    else
263→                      ''
264→                        HOSTNAME="$(hostname)"
265→                        echo "Building NixOS configuration for $HOSTNAME..."
266→                        ${nom} build ".#nixosConfigurations.$HOSTNAME.config.system.build.toplevel"
267→                      ''
268→                  }
269→                  echo "Build successful! Run 'nix run .#switch' to apply."
270→                ''
271→              );
272→            };
273→            switch = {
274→              type = "app";
275→              program = toString (
276→                pkgs.writeShellScript "switch" ''
277→                  set -eo pipefail
278→                  ${
279→                    if isDarwin then
280→                      ''
281→                        echo "Switching to darwin configuration..."
282→                        darwin-rebuild switch --flake ".#${darwinHostname}" |& ${nom}
283→                      ''
284→                    else
285→                      ''
286→                        HOSTNAME="$(hostname)"
287→                        echo "Switching to NixOS configuration for $HOSTNAME..."
288→                        sudo nixos-rebuild switch --flake ".#$HOSTNAME" |& ${nom}
289→                      ''
290→                  }
291→                  echo "Done!"
292→                ''
293→              );
294→            };
295→            fmt = {
296→              type = "app";
297→              program = toString (
298→                pkgs.writeShellScript "treefmt-wrapper" ''
299→                  exec ${config.treefmt.build.wrapper}/bin/treefmt "$@"
300→                ''
301→              );
302→            };
303→          };
304→
305→          treefmt = {
306→            projectRootFile = "flake.nix";
307→            programs = {
308→              nixfmt.enable = true;
309→              stylua.enable = true;
310→              shfmt.enable = true;
311→            };
312→            settings.global.excludes = [
313→              ".git/**"
314→              "*.lock"
315→            ];
316→          };
317→
318→          pre-commit = {
319→            check.enable = false;
320→            settings.hooks = {
321→              treefmt = {
322→                enable = true;
323→                package = config.treefmt.build.wrapper;
324→              };
325→              git-secrets = {
326→                enable = true;
327→                entry = "${pkgs.git-secrets}/bin/git-secrets --pre_commit_hook";
328→                language = "system";
329→                stages = [ "pre-commit" ];
330→                excludes = [ "^\.direnv/" ];
331→              };
332→            };
333→          };
334→
335→          devShells.default = pkgs.mkShell {
336→            shellHook = ''
337→              ${config.pre-commit.installationScript}
338→            '';
339→          };
340→        };
341→
342→      flake = {
343→        nixosConfigurations = {
344→          UM790-Pro = import ./nix/hosts/UM790-Pro { inherit inputs mkPkgs; };
345→          Still-Legend-x870 = import ./nix/hosts/Still-Legend-x870 { inherit inputs mkPkgs; };
346→        };
347→
