 1→# cage - ファイルシステムwrite制限サンドボックス
 2→# macOS: sandbox-exec, Linux: Landlock LSM
 3→{ lib, pkgs, ... }:
 4→
 5→let
 6→  isDarwin = pkgs.stdenv.isDarwin;
 7→
 8→  presetsConfig = {
 9→    presets = {
10→      base = {
11→        allow = [
12→          "."
13→          "$XDG_CACHE_HOME"
14→          "$XDG_DATA_HOME"
15→        ]
16→        ++ lib.optionals isDarwin [
17→          "/private/tmp"
18→          "/var/folders"
19→          "$HOME/Library/Caches"
20→        ]
21→        ++ lib.optionals (!isDarwin) [
22→          "/tmp"
23→        ];
24→      };
25→      npm = {
26→        allow = [
27→          "$HOME/.npm"
28→          "$HOME/.npmrc"
29→          "$HOME/.pnpm-store"
30→        ];
31→      };
32→      "git-enabled" = {
33→        "allow-git" = true;
34→      }
35→      // lib.optionalAttrs isDarwin {
36→        "allow-keychain" = true;
37→      };
38→      "claude-code" = {
39→        allow = [
40→          "$CLAUDE_CONFIG_DIR"
41→          "$HOME/.claude"
42→          "$HOME/.claude.json"
43→          "$HOME/.claude.json.backup"
44→          "$HOME/.claude.json.lock"
45→          "$HOME/.claude.lock"
46→          "$HOME/.codex"
47→        ];
48→      };
49→    };
50→    "auto-presets" = [
51→      {
52→        command = "claude";
53→        presets = [
54→          "base"
55→          "git-enabled"
56→          "npm"
57→          "claude-code"
58→        ];
59→      }
60→      {
61→        command = "codex";
62→        presets = [
63→          "base"
64→          "git-enabled"
65→          "npm"
66→          "claude-code"
67→        ];
68→      }
69→    ];
70→  };
71→
72→  configText = builtins.toJSON presetsConfig;
73→
74→  # macOS: ~/Library/Application Support/cage/
75→  # Linux: ~/.config/cage/ (XDG_CONFIG_HOME)
76→  configFile =
77→    if isDarwin then
78→      { "Library/Application Support/cage/presets.yml".text = configText; }
79→    else
80→      { ".config/cage/presets.yml".text = configText; };
81→in
82→{
83→  home.packages = [ pkgs.cage ];
84→  home.file = configFile;
85→}
